// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKey = apiKeyHeader ? headers[apiKeyHeader] : '';
const expectedKey = $env.BARK_API_KEY || '';

// Timing-safe comparison - constant time regardless of input length
// Prevents timing oracle attacks by ensuring comparison takes same time for all inputsfunction timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const MAX_LEN = 128;

  // Constant-time comparison: fold length checks into character comparison
  // Always iterate MAX_LEN, using 0 for out-of-bounds positions
  let result = 0;
  for (let i = 0; i < MAX_LEN; i++) {
    // Get character code (0 for out-of-bounds) - constant-time indexing
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    // XOR accumulates differences - if any position differs, result != 0
    result |= charA ^ charB;
  }

  // Constant-time length check - fold into result without early exit
  // Use bitwise operations to check both length conditions simultaneously
  const lenDiff = a.length ^ b.length;  // 0 if lengths equal, non-zero otherwise
  result |= lenDiff;  // If lengths differ, result becomes non-zero

  // Final check - constant-time (no branch on result value)
  return result === 0;
}

// Authentication logic:
// - If server has expectedKey configured: client MUST provide matching key
// - If client provides a key but server has none: reject (unauthorized)
// - If neither configured: allow
if ((expectedKey || providedKey) && !timingSafeEqual(providedKey || '', expectedKey || '')) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

// Validate input types (MEDIUM: prevent runtime errors from non-string values)
const input = $input.first().json || {};

// Type validation for required fields
if (typeof input.text !== 'string') {
  return [{ json: { valid: false, error: 'text must be a string' } }];
}
if (typeof input.voice_preset !== 'string') {
  return [{ json: { valid: false, error: 'voice_preset must be a string' } }];
}
if (typeof input.output_format !== 'string') {
  return [{ json: { valid: false, error: 'output_format must be a string' } }];
}

const text = input.text.trim();
const voicePreset = input.voice_preset || 'v2/en_speaker_6';
const outputFormat = input.output_format.toLowerCase();

// Valid Bark voice presets (exact match whitelist)
const validVoices = [
  'v2/en_speaker_0', 'v2/en_speaker_1', 'v2/en_speaker_2', 'v2/en_speaker_3',
  'v2/en_speaker_4', 'v2/en_speaker_5', 'v2/en_speaker_6', 'v2/en_speaker_7',
  'v2/en_speaker_8', 'v2/en_speaker_9',
  'v2/de_speaker_0', 'v2/de_speaker_1', 'v2/de_speaker_2', 'v2/de_speaker_3',
  'v2/de_speaker_4', 'v2/de_speaker_5', 'v2/de_speaker_6', 'v2/de_speaker_7',
  'v2/de_speaker_8', 'v2/de_speaker_9',
  'v2/es_speaker_0', 'v2/es_speaker_1', 'v2/es_speaker_2', 'v2/es_speaker_3',
  'v2/es_speaker_4', 'v2/es_speaker_5', 'v2/es_speaker_6', 'v2/es_speaker_7',
  'v2/es_speaker_8', 'v2/es_speaker_9',
  'v2/fr_speaker_0', 'v2/fr_speaker_1', 'v2/fr_speaker_2', 'v2/fr_speaker_3',
  'v2/fr_speaker_4', 'v2/fr_speaker_5', 'v2/fr_speaker_6', 'v2/fr_speaker_7',
  'v2/fr_speaker_8', 'v2/fr_speaker_9',
  'v2/hi_speaker_0', 'v2/hi_speaker_1', 'v2/hi_speaker_2', 'v2/hi_speaker_3',
  'v2/hi_speaker_4', 'v2/hi_speaker_5', 'v2/hi_speaker_6', 'v2/hi_speaker_7',
  'v2/hi_speaker_8', 'v2/hi_speaker_9',
  'v2/it_speaker_0', 'v2/it_speaker_1', 'v2/it_speaker_2', 'v2/it_speaker_3',
  'v2/it_speaker_4', 'v2/it_speaker_5', 'v2/it_speaker_6', 'v2/it_speaker_7',
  'v2/it_speaker_8', 'v2/it_speaker_9',
  'v2/ja_speaker_0', 'v2/ja_speaker_1', 'v2/ja_speaker_2', 'v2/ja_speaker_3',
  'v2/ja_speaker_4', 'v2/ja_speaker_5', 'v2/ja_speaker_6', 'v2/ja_speaker_7',
  'v2/ja_speaker_8', 'v2/ja_speaker_9',
  'v2/ko_speaker_0', 'v2/ko_speaker_1', 'v2/ko_speaker_2', 'v2/ko_speaker_3',
  'v2/ko_speaker_4', 'v2/ko_speaker_5', 'v2/ko_speaker_6', 'v2/ko_speaker_7',
  'v2/ko_speaker_8', 'v2/ko_speaker_9',
  'v2/pl_speaker_0', 'v2/pl_speaker_1', 'v2/pl_speaker_2', 'v2/pl_speaker_3',
  'v2/pl_speaker_4', 'v2/pl_speaker_5', 'v2/pl_speaker_6', 'v2/pl_speaker_7',
